export function mapProductToExtendedProduct(productToEdit: Product): ExtendedProduct {
  return {
    ...emptyExtendedProduct,
    ...productToEdit,
    variantes: (productToEdit as any).variantes || [],
    horario_disponible: (productToEdit as any).horario_disponible || null,
    alergenos: (productToEdit as any).alergenos || [],
    stock_minimo: (productToEdit as any).stock_minimo || 0,
    impresora_destino: (productToEdit as any).impresora_destino || "",
    ingredientes_asociados: [],
  };
}

export function createProductForCategory(
  defaultCategoryId: string,
  defaultTaxId: string,
): ExtendedProduct {
  return {
    ...emptyExtendedProduct,
    id_categoria: defaultCategoryId,
    id_impuesto: defaultTaxId,
  };
}

export function parseInputNumber(value: string) {
  if (value === "") return 0;

  const sanitizedValue = value.trim().replace(/[^0-9,.-]/g, "");
  if (sanitizedValue === "") return 0;

  const hasComma = sanitizedValue.includes(",");
  const hasDot = sanitizedValue.includes(".");

  let normalizedValue = sanitizedValue;

  if (hasComma && hasDot) {
    normalizedValue =
      sanitizedValue.lastIndexOf(",") > sanitizedValue.lastIndexOf(".")
        ? sanitizedValue.replace(/\./g, "").replace(",", ".")
        : sanitizedValue.replace(/,/g, "");
  } else if (hasComma) {
    normalizedValue = sanitizedValue.replace(",", ".");
  }

  const numValue = Number.parseFloat(normalizedValue);
  return Number.isNaN(numValue) ? 0 : numValue;
}

export function getDefaultIngredientUnit(baseUnit: string) {
  switch (baseUnit) {
    case "kg":
      return "g";
    case "l":
      return "ml";
    default:
      return baseUnit;
  }
}

export function getAvailableUnits(baseUnit: string) {
  switch (baseUnit) {
    case "kg":
      return ["kg", "g"];
    case "l":
      return ["l", "ml"];
    case "unidades":
      return ["unidades"];
    default:
      return [baseUnit];
  }
}

export function calculateIngredientSubtotal(
  ingredientInfo: any,
  quantity: number,
  selectedUnit: string,
) {
  if (!ingredientInfo) return 0;

  const baseUnit = ingredientInfo.unit;
  const baseCost = ingredientInfo.cost_base;
  let convertedQuantity = quantity;

  if (selectedUnit === baseUnit) {
    return baseCost * quantity;
  }

  if ((baseUnit === "kg" && selectedUnit === "g") || (baseUnit === "l" && selectedUnit === "ml")) {
    convertedQuantity = quantity / 1000;
  }

  return baseCost * convertedQuantity;
}

export function calculateRecipeCost(
  associatedIngredients: AssociatedIngredient[],
  ingredients: any[],
) {
  return associatedIngredients.reduce((total, assocIng) => {
    const ingredientDetails = ingredients.find(
      (ingredient) => ingredient._id === assocIng.id_ingrediente,
    );

    return (
      total +
      calculateIngredientSubtotal(
        ingredientDetails,
        assocIng.cantidad_requerida,
        assocIng.unidad_medida,
      )
    );
  }, 0);
}

export function filterAvailableIngredients(
  ingredients: any[],
  associatedIngredients: AssociatedIngredient[],
  searchTerm: string,
) {
  const existingIds = new Set(
    associatedIngredients.map((ingredient) => ingredient.id_ingrediente),
  );
  const normalizedSearch = searchTerm.toLowerCase();

  return ingredients.filter(
    (ingredient) =>
      !existingIds.has(ingredient._id) &&
      (normalizedSearch.length === 0 ||
        (ingredient.name || "").toLowerCase().includes(normalizedSearch)),
  );
}

export function createAssociatedIngredient(ingredient: any): AssociatedIngredient {
  return {
    id_ingrediente: ingredient._id,
    cantidad_requerida: 1,
    unidad_medida: getDefaultIngredientUnit(ingredient.unit),
  };
}

export function createVariant(name: string, price: number): ProductVariant {
  return {
    id: `var-${Date.now()}`,
    nombre: name,
    precio_extra: price,
    disponible: true,
  };
}

export function calculateProductMargins(
  price: number,
  taxPercent: number,
  recipeCost: number,
) {
  const basePrice = price / (1 + taxPercent / 100);
  const margin = basePrice - recipeCost;
  const marginPercent = basePrice > 0 ? (margin / basePrice) * 100 : 0;

  return {
    basePrice,
    margin,
    marginPercent,
  };
}
