import type { Category, Product } from "@/types/catalog";
import type { Carta } from "@/types/menu";

export interface ExtendedCategory extends Category {
  descripcion?: string;
  icono?: string;
  color?: string;
  orden?: number;
  activa?: boolean;
  product_count?: number;
  categoria_padre_id?: string;
  visible_en_carta?: boolean;
  impresora_destino?: string;
  bannerImage?: string;
}

export const DEFAULT_CATEGORY_ICON = "Utensils";
export const DEFAULT_CATEGORY_COLOR = "#9B6EFD";

export function createEmptyCategoryData(order = 0): Partial<ExtendedCategory> {
  return {
    nombre_categoria: "",
    descripcion: "",
    icono: DEFAULT_CATEGORY_ICON,
    color: DEFAULT_CATEGORY_COLOR,
    bannerImage: "",
    orden: order,
    categoria_padre_id: "",
    visible_en_carta: true,
    impresora_destino: "",
  };
}

export function categoryToFormData(category: ExtendedCategory): Partial<ExtendedCategory> {
  return {
    nombre_categoria: category.nombre_categoria,
    descripcion: category.descripcion || "",
    icono: category.icono || DEFAULT_CATEGORY_ICON,
    color: category.color || DEFAULT_CATEGORY_COLOR,
    bannerImage: category.bannerImage || "",
    orden: category.orden || 0,
    categoria_padre_id: category.categoria_padre_id || "",
    visible_en_carta: category.visible_en_carta !== false,
    impresora_destino: category.impresora_destino || "",
  };
}

export function getAssignedProducts(products: Product[], categoryId?: string) {
  if (!categoryId) return [];
  return products.filter((product) => product.id_categoria === categoryId);
}

export function getUnassignedProducts(
  products: Product[],
  assignedProducts: Product[],
  searchTerm: string,
) {
  const assignedIds = new Set(assignedProducts.map((product) => product.id));
  const normalizedSearch = searchTerm.toLowerCase();

  return products.filter(
    (product) =>
      !assignedIds.has(product.id) &&
      product.nombre_producto.toLowerCase().includes(normalizedSearch),
  );
}

export function getParentCategoryOptions(
  allCategories: ExtendedCategory[],
  category: ExtendedCategory | null,
) {
  if (!category) return allCategories;
  return allCategories.filter(
    (candidate) =>
      candidate.id !== category.id && candidate.categoria_padre_id !== category.id,
  );
}

export function normalizeCarta(carta: Partial<Carta>): Partial<Carta> {
  return carta;
}

export function dedupeCartaCategories(
  categoryIds: string[] | undefined,
) {
  if (!categoryIds) return [];
  return [...new Set(categoryIds)];
}

export function categoryCount(categoryIds: string[] | undefined) {
  return categoryIds?.length || 0;
}

export function isCategoryInCarta(
  categoryIds: string[] | undefined,
  categoryId: string,
) {
  return categoryIds?.includes(categoryId) || false;
}

export function removeCategoryFromCarta(
  categoryIds: string[] | undefined,
  categoryId: string,
) {
  return categoryIds?.filter((id) => id !== categoryId) || [];
}

export function addCategoryToCarta(
  categoryIds: string[] | undefined,
  categoryId: string,
): string[] {
  if (categoryIds?.includes(categoryId)) return categoryIds;
  return [...(categoryIds || []), categoryId];
}
